```json
{
  "global": "Navigate a hotel booking interface to search for hotels in Las Vegas for 2 guests for 7 nights starting April 10, sort results by price ascending, and return the cheapest hotel with its total cost.",
  "subtasks": [
    {
      "subtask": "Open the hotel search page within the booking application",
      "atomics": [
        "Click the 'Hotels' navigation link or navigate to the hotel search URL",
        "Confirm the hotel search form is rendered and interactive"
      ]
    },
    {
      "subtask": "Populate the search form with all required parameters",
      "atomics": [
        "Type 'Las Vegas, NV' into the destination or location input field",
        "Open the check-in date picker and select April 10",
        "Open the check-out date picker and select April 17 (7 nights after April 10)",
        "Set the adults/guests selector to 2"
      ]
    },
    {
      "subtask": "Submit the search and wait for hotel listings to load",
      "atomics": [
        "Click the 'Search' or 'Find Hotels' submit button",
        "Wait for the results list container to become visible and populated"
      ]
    },
    {
      "subtask": "Sort the results list by price ascending to surface the cheapest option",
      "atomics": [
        "Click the 'Sort By' control and select the 'Price: Low to High' option",
        "Confirm the results re-render with the lowest-priced hotel at the top"
      ]
    },
    {
      "subtask": "Extract the hotel name and total price from the top-ranked result",
      "atomics": [
        "Read the hotel name text from the first result card",
        "Read the total price (7-night cost for 2 guests) displayed on the first result card"
      ]
    }
  ],
  "global_atomics": [
    "Assert the results page header or filter summary reflects guests=2, check-in=April 10, check-out=April 17 to confirm no parameter was silently reset",
    "Report the extracted hotel name and minimum total cost as the final answer"
  ],
  "gold_actions": {
    "global": "Execute hotel search with destination='Las Vegas, NV', check_in='April 10', check_out='April 17', guests=2; apply sort='Price: Low to High'; read hotel name and total price from result[0].",
    "subtasks": [
      {
        "subtask": "Navigate to the hotel search form",
        "atomics": [
          "click(element='Hotels nav link') or navigate_to(path='/hotels')",
          "assert_visible(element='hotel-search-form')"
        ]
      },
      {
        "subtask": "Fill in destination, check-in date, check-out date, and guest count",
        "atomics": [
          "type(field='destination-input', value='Las Vegas, NV')",
          "click(field='check-in-datepicker') and select_date(date='April 10')",
          "click(field='check-out-datepicker') and select_date(date='April 17')",
          "set_value(field='adults-selector', value=2)"
        ]
      },
      {
        "subtask": "Submit the search form and await results",
        "atomics": [
          "click(button='Search Hotels')",
          "wait_for(element='results-list', condition='visible and non-empty')"
        ]
      },
      {
        "subtask": "Apply price-ascending sort to the results",
        "atomics": [
          "click(element='sort-dropdown') and select_option(label='Price: Low to High')",
          "assert results_list[0].price <= results_list[1].price"
        ]
      },
      {
        "subtask": "Read hotel name and 7-night total price from the first result card",
        "atomics": [
          "read_text(selector='results-list > result-card:first-child > hotel-name')",
          "read_text(selector='results-list > result-card:first-child > total-price')"
        ]
      }
    ],
    "global_atomics": [
      "assert_text_contains(element='results-summary', patterns=['2 guests', 'Apr 10', 'Apr 17', 'Las Vegas']) to validate search parameters were not reset",
      "output(answer={'hotel_name': <extracted_name>, 'total_cost_usd': <extracted_price>, 'nights': 7, 'guests': 2, 'check_in': 'April 10', 'check_out': 'April 17'})"
    ]
  }
}
```
